import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import reportWebVitals from './reportWebVitals';

function Header() {
  <header>
    <p id="sait_name">DSpark Store</p>
  </header>
}

function Wrapper() {
  return(
  <div id="Wrapper">
    <Header />
    <div id="content">
      <div id="news">
        <p>News</p>
        <div id="news_place">
          <p>Актуальная новость</p>
        </div>
      </div>
      <div id="game_shop">
        <p>Game Shop</p>
      </div>
      <div id="item_store">
        <p>Item_store</p>
      </div>
    </div>
  </div>
  )
}


const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <Wrapper />
);

// If you want to start measuring performance in your app, pass a function
